/**
 * NPC Generator Data Tables
 * All random tables, archetype profiles, and feat templates for procedural NPC generation.
 * No AI — pure lists and calculation.
 */

import type { ActorAttribute } from './constants.js';

// ═══════════════════════════════════════════════════════════════
// TYPES
// ═══════════════════════════════════════════════════════════════

export interface MetatypeProfile {
  maxes: Record<ActorAttribute, number>;
  anarchyBonus: number;
  nameFr: string;
  nameEn: string;
  img: string;
}

export interface PowerLevelProfile {
  budget: number;
  maxedAttributes: number;
  skillMax: number;
  labelFr: string;
  labelEn: string;
}

/** Bilingual text: FR and EN versions */
export interface BiText { fr: string; en: string; }
export function bi(fr: string, en: string): BiText { return { fr, en }; }

export interface FeatTemplate {
  name: string;
  nameEn?: string;
  featType: string;
  cost: string;
  rating: number;
  description: string;
  descriptionEn?: string;
  essenceCost: number;
  isBioware: boolean;
  armorValue: number;
  bonusLightDamage: number;
  bonusSevereDamage: number;
  bonusPhysicalThreshold: number;
  bonusMentalThreshold: number;
  bonusMatrixThreshold: number;
  bonusAnarchy: number;
  rrList: { rrType: string; rrValue: number; rrTarget: string; rrLabel: string }[];
  // Weapon fields
  weaponType?: string;
  damageValue?: string;
  damageValueBonus?: number;
  vdMode?: string;
  vdCustomValue?: number;
  vdAttribute?: string;
  vdBonus?: number;
  damageType?: string;
  meleeRange?: string;
  shortRange?: string;
  mediumRange?: string;
  longRange?: string;
  // Cyberdeck fields
  firewall?: number;
  attack?: number;
  // Awakened fields
  astralPerception?: boolean;
  astralProjection?: boolean;
  sorcery?: boolean;
  conjuration?: boolean;
  adept?: boolean;
  // Emerged fields
  matrixAccess?: boolean;
  complexFormWeaving?: boolean;
  spriteCompilation?: boolean;
  biofeedback?: boolean;
  // First feat flag (first trait costs 0 base instead of +3)
  isFirstFeat?: boolean;
  // Flags
  bookmarked?: boolean;
  /** Nuyen cost for budget calculation */
  nuyenCost: number;
}

export interface ArchetypeProfile {
  labelFr: string;
  labelEn: string;
  primaryAttributes: ActorAttribute[];
  primarySkills: Record<string, number>;
  secondarySkills: Record<string, number>;
  requiredSpecs: string[];
  optionalSpecs: string[];
  cyberwarePool: string[];
  weaponPool: string[];
  spellPool?: string[];
  adeptPowerPool?: string[];
  complexFormPool?: string[];
  equipmentPool: string[];
  traitPool: string[];
  armorRange: [number, number];
  streetNameTheme: string;
  isAwakened?: boolean;
  isEmerged?: boolean;
  maxEssenceLoss: number; // 0 for mages
}

